const records = $input.first().json.list || [];

if (records.length === 0) {
  console.log('Keine Kandidaten mit Status=fotos_geladen.');
  return [];
}

// ⚠️ Chat-ID der Voting-Gruppe-Liste eintragen:
const chatId = '811831595';

return records.map(r => {
  const photos = (() => { try { return JSON.parse(r.Fotos || '[]'); } catch(e) { return []; } })();
  const caption = `👤 <b>${r.Username || 'Unbekannt'}</b>`
    + (r.Alter ? ` · ${r.Alter} J.` : '')
    + (r.Stadt ? ` · ${r.Stadt}`    : '')
    + `\n🔗 ${r.ProfilUrl}`;

  if (photos.length > 0) {
    const media = photos.map((url, i) => ({
      type: 'photo',
      media: url,
      ...(i === 0 ? { caption, parse_mode: 'HTML' } : {})
    }));
    return { json: {
      _nocodb_id:  r.Id,
      _apiMethod:  'sendMediaGroup',
      _body:       JSON.stringify({ chat_id: chatId, media })
    }};
  } else {
    return { json: {
      _nocodb_id:  r.Id,
      _apiMethod:  'sendMessage',
      _body:       JSON.stringify({ chat_id: chatId, text: caption, parse_mode: 'HTML' })
    }};
  }
});

// Telegram Message-ID aus der API-Antwort extrahieren
const result   = $input.item.json.result || {};
const nocodb_id = $('📦 Telegram Payload bauen').item.json._nocodb_id;

// sendMediaGroup gibt Array zurück, sendMessage ein Objekt
const isArray = Array.isArray(result);
const msgId = isArray
  ? (result[0]?.message_id || '')
  : (result.message_id || '');

return [{ json: { _nocodb_id: nocodb_id, msgId: String(msgId) } }];

